pub struct UnifiedBridge {
    registry:                Arc<OntologyRegistry>,
    authorized_super_domains: &'static [SuperDomain],   // e.g., &[Healthcare]
    actor_role:               &'static str,
    actor_clearance:          ClearanceLevel,
    audit_sink:               Arc<dyn AuditSink>,
}

impl UnifiedBridge {
    /// Hot-path RBAC filter. DataFusion lowers this to a single masked predicate
    /// over the high byte of OwlIdentity. No per-row policy evaluation.
    #[inline] pub fn authorize(&self, owl: OwlIdentity) -> Result<()> {
        let family = owl.family();
        let sd = FAMILY_TO_SUPER_DOMAIN[family.0 as usize];
        if !self.authorized_super_domains.contains(&sd) {
            return Err(RbacError::OutOfScope { actor: self.actor_role, requested: sd });
        }
        let policy = &SUPER_DOMAINS[sd as usize].rbac_policy;
        if self.actor_clearance.0 < policy.clearance_floor.0 {
            return Err(RbacError::InsufficientClearance);
        }
        if policy.audit_required {
            self.audit_sink.emit(AuditEntry::new(self.actor_role, owl, sd));
        }
        Ok(())
    }
}
