**Unified bridge — 4-stage authorize:**

```rust
impl UnifiedBridge {
    /// Hot-path authorization. All four checks lower to bitmask predicates
    /// in DataFusion — combined into one predicate vector at plan time.
    #[inline] pub fn authorize(
        &self,
        owl:        OwlIdentity,
        row_tenant: TenantId,
        op:         Operation,
    ) -> Result<RowAccess> {
        // 1. CHINESE WALL: tenant isolation (single u32 compare)
        if row_tenant != self.tenant.tenant_id {
            return Err(RbacError::CrossTenantViolation);
        }
        // Crypto backstop: even if predicate elided, row payload is wrapped
        // with a DEK only this tenant's bridge holds.

        // 2. SUPER DOMAIN: which super domain this basin belongs to
        let sd = FAMILY_TO_SUPER_DOMAIN[owl.family().0 as usize];
        let role_name = self.tenant.role_bindings.iter()
            .find_map(|(s, r)| (*s == sd).then_some(*r))
            .ok_or(RbacError::NoSuperDomainAccess)?;

        // 3. ROLE GROUP: lookup role within super domain
        let role = SUPER_DOMAINS[sd as usize].role_groups.iter()
            .find(|r| r.role_name == role_name)
            .ok_or(RbacError::UnknownRole)?;
        if !role.permissions.allows(op) {
            return Err(RbacError::OperationNotPermitted);
        }

        // 4. SLOT REDACTION: per-slot mask within role
        let slot = owl.slot();
        let access = match op {
            Operation::Read  if role.redaction_mask.readable_slots.contains(slot) => RowAccess::Full,
            Operation::Read  if role.redaction_mask.redacted_slots.contains(slot) => RowAccess::Redacted,
            Operation::Read                                                       => RowAccess::Hidden,
            Operation::Write if role.redaction_mask.writable_slots.contains(slot) => RowAccess::Full,
            Operation::Write                                                       => return Err(RbacError::SlotNotWritable),
            // ...
        };

        if role.audit_required {
            self.audit_sink.emit(AuditEntry::new(self.tenant, role_name, owl, op));
        }
        Ok(access)
    }
}
```

